#include<bits/stdc++.h>
using namespace std;
int n,a[205],b[205][205],c[205],t,dp[205],ans;
void print(int x) {
	if(x==0) return ;
	print(c[x]);
	cout<<x<<' ';
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<n;i++)
    {
		for(int j=i+1;j<=n;j++)
        {
			int x;
			cin>>x;
			if(x==1) b[i][j]=1;
		}
	}
	for (int i=1;i<=n;i++)
    {
		for(int j=1;j<=n;j++)
        {
			if(b[j][i]&&dp[j]>dp[i])
            {
				dp[i]=dp[j];
				c[i]=j;
			}
		}
		dp[i]+=a[i];
		if(dp[i]>ans)
        {
			ans=dp[i];
			t=i;
		}
	}
	print(t);
    cout<<'\n'<<ans;
	return 0;
}
